function drawSketch(){const floor=activeFloor(),c=$('#sketchCanvas');if(!c)return;const x=c.getContext('2d'),scale=ensureSketch().viewport.scale||1;x.clearRect(0,0,c.width,c.height);x.lineCap='round';x.lineJoin='round';for(const item of floor.items||[]){const pts=item.points||[];if(!pts.length)continue;if(item.kind==='interiorLine'){if(pts.length<2)continue;x.save();x.beginPath();x.moveTo(pts[0].x,pts[0].y);x.lineTo(pts[1].x,pts[1].y);x.strokeStyle='#687785';x.lineWidth=3/scale;x.setLineDash([8/scale,5/scale]);x.stroke();x.restore();continue}if(item.kind==='cutout'){if(pts.length<2)continue;const a=pts[0],b=pts[1],left=Math.min(a.x,b.x),top=Math.min(a.y,b.y),w=Math.abs(b.x-a.x),h=Math.abs(b.y-a.y);x.save();x.fillStyle=item.subtype==='garage'?'rgba(183,121,31,.13)':'rgba(180,35,24,.13)';x.strokeStyle=item.subtype==='garage'?'#9a6700':'#b42318';x.lineWidth=3/scale;x.setLineDash([9/scale,6/scale]);x.fillRect(left,top,w,h);x.strokeRect(left,top,w,h);x.setLineDash([]);x.fillStyle=item.subtype==='garage'?'#7a5200':'#8d1b13';x.font=`bold ${14/scale}px system-ui`;x.fillText(item.label||'CUT-OUT',left+7/scale,top+20/scale);x.font=`${12/scale}px system-ui`;x.fillText(`${item.length.toFixed(1)}' × ${item.width.toFixed(1)}'`,left+7/scale,top+38/scale);x.restore();continue}if(item.kind!=='pointFootprint')continue;x.save();x.beginPath();x.moveTo(pts[0].x,pts[0].y);for(const p of pts.slice(1))x.lineTo(p.x,p.y);if(item.closed){x.closePath();x.fillStyle='rgba(35,93,140,.10)';x.fill()}x.strokeStyle='#17324d';x.lineWidth=5/scale;x.stroke();(item.segments||[]).forEach((seg,i)=>{if(!seg.calculated)return;const a=pts[i],b=i===pts.length-1&&item.closed?pts[0]:pts[i+1];if(!a||!b)return;x.save();x.beginPath();x.moveTo(a.x,a.y);x.lineTo(b.x,b.y);x.strokeStyle='#b7791f';x.lineWidth=6/scale;x.setLineDash([10/scale,7/scale]);x.stroke();x.restore()});pts.forEach((p,i)=>{x.beginPath();x.arc(p.x,p.y,(i===0?10:7)/scale,0,Math.PI*2);x.fillStyle=i===0?'#1d7a43':'#17324d';x.fill();x.lineWidth=3/scale;x.strokeStyle='#fff';x.stroke()});(item.segments||[]).forEach((seg,i)=>{const a=pts[i],b=i===pts.length-1&&item.closed?pts[0]:pts[i+1];if(!a||!b)return;const mx=(a.x+b.x)/2,my=(a.y+b.y)/2;x.fillStyle='#17324d';x.font=`bold ${15/scale}px system-ui`;x.fillText(`${Number(seg.length).toFixed(seg.length%1?2:0)}'${seg.calculated?' CALC':''}`,mx+7/scale,my-8/scale)});if(item.closed){const cx=pts.reduce((a,p)=>a+p.x,0)/pts.length,cy=pts.reduce((a,p)=>a+p.y,0)/pts.length;x.font=`bold ${18/scale}px system-ui`;x.fillText(formatArea(polygonArea(pts)),cx-30/scale,cy)}x.restore()}const fp=activeFootprint();if(fp&&!fp.closed&&fp.points.length){const current=fp.points[fp.points.length-1],guides=guidePointsFor(fp);x.save();for(const g of guides){x.beginPath();x.moveTo(current.x,current.y);x.lineTo(g.x,g.y);x.strokeStyle='rgba(35,93,140,.20)';x.lineWidth=2/scale;x.setLineDash([5/scale,7/scale]);x.stroke();x.setLineDash([]);x.beginPath();x.arc(g.x,g.y,12/scale,0,Math.PI*2);x.fillStyle='rgba(255,255,255,.96)';x.fill();x.lineWidth=3/scale;x.strokeStyle='#235d8c';x.stroke()}for(const g of closureAssistPointsFor(fp)){if(g.source){x.beginPath();x.moveTo(g.source.x,g.source.y);x.lineTo(g.x,g.y);x.strokeStyle='rgba(183,121,31,.28)';x.lineWidth=2/scale;x.setLineDash([4/scale,7/scale]);x.stroke()}x.beginPath();x.moveTo(current.x,current.y);x.lineTo(g.x,g.y);x.strokeStyle='rgba(183,121,31,.55)';x.lineWidth=2.5/scale;x.setLineDash([7/scale,6/scale]);x.stroke();x.setLineDash([]);x.beginPath();x.arc(g.x,g.y,14/scale,0,Math.PI*2);x.fillStyle='#fff8e6';x.fill();x.lineWidth=4/scale;x.strokeStyle='#b7791f';x.stroke();x.fillStyle='#8a5a13';x.font=`bold ${12/scale}px system-ui`;x.textAlign='center';x.fillText(g.type==='direct'?'CLOSE':'ALIGN',g.x,g.y-20/scale)}x.beginPath();x.arc(current.x,current.y,15/scale,0,Math.PI*2);x.fillStyle='#235d8c';x.fill();x.lineWidth=4/scale;x.strokeStyle='#fff';x.stroke();if(fp.segments.length===0){x.beginPath();x.arc(current.x,current.y,23/scale,0,Math.PI*2);x.lineWidth=3/scale;x.strokeStyle='rgba(29,122,67,.55)';x.stroke();x.fillStyle='#1d7a43';x.font=`bold ${15/scale}px system-ui`;x.textAlign='center';x.fillText('START',current.x,current.y+43/scale)}x.restore()}if(sketchAuxStart&&ensureSketch().drawMode==='point'&&sketchAuxTool!=='exterior'){x.save();x.beginPath();x.arc(sketchAuxStart.x,sketchAuxStart.y,11/scale,0,Math.PI*2);x.fillStyle='#fff';x.fill();x.lineWidth=4/scale;x.strokeStyle=sketchAuxTool==='interiorLine'?'#687785':sketchAuxTool==='garageCutout'?'#9a6700':'#b42318';x.stroke();x.fillStyle=x.strokeStyle;x.font=`bold ${12/scale}px system-ui`;x.textAlign='center';x.fillText('START',sketchAuxStart.x,sketchAuxStart.y-17/scale);x.restore()}if(smartStroke){const close=smartCloseTarget(smartStroke),dx=smartStroke.to.x-smartStroke.from.x,dy=smartStroke.to.y-smartStroke.from.y;let h=Math.atan2(dy,dx)*180/Math.PI;if(h<0)h+=360;const sn=Math.round(h/45)*45%360,diff=Math.abs(((h-sn+540)%360)-180),hh=diff<=14?sn:h,len=Math.max(35,Math.hypot(dx,dy)),rad=hh*Math.PI/180,to=close?{x:close.start.x,y:close.start.y}:{x:smartStroke.from.x+Math.cos(rad)*len,y:smartStroke.from.y+Math.sin(rad)*len},previewColor=close?'#b7791f':diff<=14?'#1d7a43':'#2f6ea6';x.save();if(close){x.beginPath();x.arc(close.start.x,close.start.y,20/scale,0,Math.PI*2);x.fillStyle='rgba(255,248,230,.96)';x.fill();x.lineWidth=5/scale;x.strokeStyle='#b7791f';x.stroke()}x.beginPath();x.moveTo(smartStroke.from.x,smartStroke.from.y);x.lineTo(to.x,to.y);x.strokeStyle=previewColor;x.lineWidth=5/scale;x.setLineDash([10/scale,6/scale]);x.stroke();x.setLineDash([]);x.beginPath();x.arc(to.x,to.y,10/scale,0,Math.PI*2);x.fillStyle='#fff';x.fill();x.lineWidth=3/scale;x.strokeStyle=previewColor;x.stroke();x.fillStyle=previewColor;x.font=`bold ${13/scale}px system-ui`;x.textAlign='center';x.fillText(close?'RELEASE TO CLOSE':diff<=14?`${Math.round(sn)}° SNAP`:'CUSTOM',to.x,to.y-17/scale);x.restore()}}


function fieldLabel(f){return f['Field Label']||f.Question||f['Field ID']||'Review item'}
function fieldLocation(f){return f.Tab==='Exit Interview'?'Exit Interview':(f.Tab||'Property')}
function goToReviewField(tab,id){state.activeTab=tab;buildTabs();render();scrollTo(0,0);setTimeout(()=>{const el=document.querySelector(`.field[data-id="${CSS.escape(id)}"]`);if(el){el.scrollIntoView({behavior:'smooth',block:'center'});el.classList.add('review-focus');setTimeout(()=>el.classList.remove('review-focus'),1800)}},80)}
function reviewItemHtml(item){const cls=item.level==='error'?'review-error':item.level==='warning'?'review-warning':'review-info';const icon=item.level==='error'?'✕':item.level==='warning'?'⚠':'ℹ';return`<button class="review-item ${cls}" data-review-tab="${esc(item.tab)}" data-review-id="${esc(item.id)}"><span class="review-icon">${icon}</span><span class="review-copy"><b>${esc(item.title)}</b><small>${esc(item.reason)}</small><em>${esc(item.tab)}${item.section?' • '+esc(item.section):''}</em></span><span class="review-arrow">›</span></button>`}
function renderReview(){
  let visible=CFG.app.filter(f=>truth(f.Visible??'Yes')&&ruleVisible(f['Visibility Rule']));
  let activeGroups=activeFollowGroups();
  let followVisible=CFG.followups.filter(f=>activeGroups.has(f['Follow-Up Group'])&&ruleVisible(f['Visibility Rule']));
  let allVisible=[...visible,...followVisible];
  let items=[];
  allVisible.forEach(f=>{let id=f['Field ID'],v=state.values[id],empty=v===undefined||v===''||(Array.isArray(v)&&!v.length);if(truth(f.Required)&&empty)items.push({level:'error',id,title:fieldLabel(f),reason:'Required response is incomplete.',tab:fieldLocation(f),section:f.Section||f['Follow-Up Group']||''})});
  allVisible.forEach(f=>{let id=f['Field ID'];if(state.flags[id])items.push({level:'warning',id,title:fieldLabel(f),reason:state.notes[id]&&String(state.notes[id]).trim()?`Flagged: ${String(state.notes[id]).trim()}`:'Flagged during the inspection. Open the item to review or clear the flag.',tab:fieldLocation(f),section:f.Section||f['Follow-Up Group']||''})});
  let notes=Object.values(state.notes).filter(v=>String(v).trim()).length,flags=Object.values(state.flags).filter(Boolean).length,photos=Object.values(state.photos).reduce((a,b)=>a+b.length,0);
  let errors=items.filter(x=>x.level==='error').length,warnings=items.filter(x=>x.level==='warning').length;
  $('#screen').innerHTML=`<h2 class="section-title">Inspection Review</h2><div class="review-summary"><div><b>${errors}</b><span>Incomplete</span></div><div><b>${warnings}</b><span>Flagged</span></div><div><b>${notes}</b><span>Notes</span></div><div><b>${photos}</b><span>Photos</span></div></div>${items.length?`<div class="review-heading"><b>Items requiring review</b><span>Tap an item to open it</span></div><div class="review-items">${items.map(reviewItemHtml).join('')}</div>`:'<div class="success review-complete"><b>✓ Inspection review complete</b><br>No required or flagged items are outstanding.</div>'}<div class="review-card"><b>Inspection totals</b><div class="review-line"><span>Bedrooms</span><b>${Number(state.values.bedroom_count||0)}</b></div><div class="review-line"><span>Full bathrooms</span><b>${Number(state.values.full_bath_count||0)}</b></div><div class="review-line"><span>Half bathrooms</span><b>${Number(state.values.half_bath_count||0)}</b></div><div class="review-line"><span>Smoke / CO detectors</span><b>${Number(state.values.smoke_co_count||0)}</b></div></div><div class="review-card"><b>Exit Interview groups</b><div class="small">${[...activeGroups].map(esc).join(' • ')}</div></div><div class="actions"><button class="action" id="exportBtn">Export JSON</button><button class="action secondary" id="resetBtn">Reset Inspection</button></div>`;
  document.querySelectorAll('[data-review-id]').forEach(b=>b.onclick=()=>goToReviewField(b.dataset.reviewTab,b.dataset.reviewId));
  $('#exportBtn').onclick=()=>{let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='clipboard-v6-0-inspection.json';a.click();URL.revokeObjectURL(a.href)};
  $('#resetBtn').onclick=()=>{if(confirm('Clear this inspection?')){localStorage.removeItem(STORAGE_KEY);localStorage.removeItem('clipboard-v4-4-state');localStorage.removeItem('clipboard-v4-3-2-state');localStorage.removeItem('clipboard-v4-3-state');localStorage.removeItem('clipboard-v4-2-1-state');localStorage.removeItem('clipboard-v4-state');state={values:{},notes:{},flags:{},photos:{},sketch:{strokes:[],background:'',viewport:{scale:1,x:0,y:0}},activeTab:'Property'};[...CFG.app,...CFG.followups].forEach(f=>{if(f['Default Value']!==undefined&&f['Default Value']!=='')state.values[f['Field ID']]=f['Default Value']});buildTabs();render();updateCounters()}}}
init();